# 3. YARDIMCI ARAÇLAR VE MASKELER (FİNANS VE SKT İÇİN ORTAK)
def mask_tarih_otomatik(event):
    entry = event.widget
    if event.keysym in ("BackSpace", "Delete"): return
    text = entry.get()
    clean = "".join([c for c in text if c.isdigit()])
    formatted = ""
    if len(clean) > 0: formatted = clean[:4]
    if len(clean) >= 5: formatted += "-" + clean[4:6]
    if len(clean) >= 7: formatted += "-" + clean[6:8]
    if text != formatted:
        entry.delete(0, tk.END)
        entry.insert(0, formatted)

def mask_para_birimi(event):
    entry = event.widget
    if event.keysym in ("BackSpace", "Delete", "Left", "Right", "Tab"): return
    try:
        val = entry.get().replace(".", "")
        if "," in val:
            parts = val.split(",")
            int_part = parts[0]
            dec_part = parts[1]
        else:
            int_part = val
            dec_part = None
            
        if int_part.isdigit():
            new_int = "{:,}".format(int(int_part)).replace(",", ".")
        else:
            new_int = int_part
            
        res = new_int
        if dec_part is not None: res += "," + dec_part
        if entry.get() != res:
            entry.delete(0, tk.END)
            entry.insert(0, res)
    except: pass

def temizle_para(text):
    if not text: return 0.0
    try:
        clean = text.replace(".", "").replace(",", ".")
        return float(clean)
    except: return 0.0

class CreateToolTip(object):
    def __init__(self, widget, text='widget info'):
        self.waittime = 500
        self.wraplength = 300
        self.widget = widget
        self.text = text
        self.widget.bind("<Enter>", self.enter)
        self.widget.bind("<Leave>", self.leave)
        self.widget.bind("<ButtonPress>", self.leave)
        self.id = None
        self.tw = None

    def enter(self, event=None): self.schedule()
    def leave(self, event=None): self.unschedule(); self.hidetip()
    def schedule(self): self.unschedule(); self.id = self.widget.after(self.waittime, self.showtip)
    def unschedule(self):
        id = self.id
        self.id = None
        if id: self.widget.after_cancel(id)

    def showtip(self, event=None):
        if self.tw: return
        x = y = 0
        try:
            x, y, cx, cy = self.widget.bbox("insert")
            x += self.widget.winfo_rootx() + 25
            y += self.widget.winfo_rooty() + 20
        except: return
        self.tw = tk.Toplevel(self.widget)
        self.tw.wm_overrideredirect(True)
        self.tw.wm_geometry("+%d+%d" % (x, y))
        self.tw.wm_attributes("-topmost", True)
        label = tk.Label(self.tw, text=self.text, justify='left', background="#ffffe0", relief='solid', borderwidth=1, wraplength=self.wraplength)
        label.pack(ipadx=5, ipady=5)

    def hidetip(self):
        tw = self.tw
        self.tw = None
        if tw: tw.destroy()

class ModernButton(tk.Canvas):
    def __init__(self, parent, text, command=None, width=120, height=35, corner_radius=10, bg_color="#3b82f6", fg_color="white", hover_color=None, font=FONT_BOLD, **kwargs):
        super().__init__(parent, width=width, height=height, bg=parent["bg"], highlightthickness=0, **kwargs)
        self.command = command; self.text = text; self.bg_color = bg_color
        self.hover_color = hover_color if hover_color else bg_color
        self.fg_color = fg_color; self.corner_radius = corner_radius; self.font = font
        self.bind("<Button-1>", self._on_click); self.bind("<Enter>", self._on_enter); self.bind("<Leave>", self._on_leave)
        self._draw(self.bg_color)
    def _draw(self, color):
        try:
            if not self.winfo_exists(): return
            self.delete("all"); w, h = int(self["width"]), int(self["height"]); r = self.corner_radius
            points = (r, 0, w-r, 0, w, 0, w, r, w, h-r, w, h, w-r, h, r, h, 0, h, 0, h-r, 0, r, 0, 0)
            self.create_polygon(points, fill=color, smooth=True, outline=color)
            self.create_text(w/2, h/2, text=self.text, fill=self.fg_color, font=self.font, justify="center", tag="text")
        except: pass
    def _on_click(self, event):
        if self.command: self.command()
    def _on_enter(self, event): self.configure(cursor="hand2"); self._draw(self.hover_color)
    def _on_leave(self, event): self.configure(cursor="arrow"); self._draw(self.bg_color)
    def update_color(self, color): self.bg_color = color; self._draw(color)

class DraggableNotebook(tk.Frame):
    def __init__(self, master, on_reorder=None, **kwargs):
        super().__init__(master, bg=TM.get_color("bg_main"), **kwargs)
        
        self.on_reorder = on_reorder
        self.tab_frames = [] 
        self.current_tab = None
        self._drag_data = {"tab": None, "start_y": 0} # Sürükleme hafızası artık Y ekseninde
        
        # --- SOL MENÜ (SIDEBAR) ALANI ---
        self.sidebar = tk.Frame(self, bg=TM.get_color("bg_sidebar"), width=325) # 240 olan genişliği 300 yaptık
        self.sidebar.pack(side="left", fill="y")
        self.sidebar.pack_propagate(False) # Genişliği 300px'de sabitle
        
        # Dikey Kaydırma için Canvas ve Scrollbar
        self.canvas = tk.Canvas(self.sidebar, bg=TM.get_color("bg_sidebar"), highlightthickness=0)
        self.scrollbar = ttk.Scrollbar(self.sidebar, orient="vertical", command=self.canvas.yview)
        
        self.tab_container = tk.Frame(self.canvas, bg=TM.get_color("bg_sidebar"))
        self.canvas_window = self.canvas.create_window((0, 0), window=self.tab_container, anchor="nw")
        
        self.canvas.configure(yscrollcommand=self.scrollbar.set)
        
        self.canvas.pack(side="left", fill="both", expand=True)
        # Sadece sekmeler ekrana sığmazsa scrollbar görünür
        self.scrollbar.pack(side="right", fill="y")
        
        self.tab_container.bind("<Configure>", self._on_tab_container_configure)
        self.canvas.bind("<Configure>", self._on_canvas_configure)
        
        # Fare tekerleği ile dikey kaydırma
        self.canvas.bind_all("<MouseWheel>", self._on_mousewheel)
        
        # --- SAĞ İÇERİK ALANI ---
        self.content_area = tk.Frame(self, bg=TM.get_color("bg_main"))
        self.content_area.pack(side="left", fill="both", expand=True)

    def _on_tab_container_configure(self, event):
        self.canvas.configure(scrollregion=self.canvas.bbox("all"))

    def _on_canvas_configure(self, event):
        self.canvas.itemconfig(self.canvas_window, width=event.width)

    def _on_mousewheel(self, event):
        # Sadece fare sol menünün üzerindeyse kaydır
        if not self.winfo_exists(): return
        try:
            x, y = self.winfo_pointerxy()
            widget = self.winfo_containing(x, y)
            if widget and (widget == self.canvas or widget.master == self.tab_container or getattr(widget.master, 'master', None) == self.tab_container):
                self.canvas.yview_scroll(int(-1*(event.delta/120)), "units")
        except: pass

    def add(self, child, text="Tab"):
        bg_color = TM.get_color("bg_sidebar")
        fg_color = "#94a3b8" # Pasif yazı rengi (Açık gri)
        
        # --- DİKEY SEKME TASARIMI ---
        btn = tk.Frame(self.tab_container, bg=bg_color, cursor="hand2")
        btn.pack(side="top", fill="x", pady=2, padx=(5, 5))
        
        # Aktif sekmeyi belli edecek sol şerit (İndikatör)
        indicator = tk.Frame(btn, bg=bg_color, width=4)
        indicator.pack(side="left", fill="y")
        
        lbl = tk.Label(btn, text=text, font=("Segoe UI", 10, "bold"), bg=bg_color, fg=fg_color, cursor="hand2", anchor="w", padx=15, pady=12)
        lbl.pack(side="left", fill="both", expand=True)
        
        tab_data = {"child": child, "text": text, "btn": btn, "lbl": lbl, "ind": indicator}
        self.tab_frames.append(tab_data)
        
        # --- SÜRÜKLE BIRAK (DRAG & DROP) DİKEY OLAYLARI ---
        def on_press(e, t=tab_data):
            self._drag_data["tab"] = t
            self._drag_data["start_y"] = e.y_root
            self.select(t["child"]) # Tıklandığında hemen seçili yap
            
        def on_motion(e):
            if not self._drag_data["tab"]: return
            dy = e.y_root - self._drag_data["start_y"]
            if abs(dy) < 5: return # Titremeyi önlemek için tolerans
            
            dragged_tab = self._drag_data["tab"]
            current_idx = self.tab_frames.index(dragged_tab)
            
            # Farenin menü içindeki Y koordinatını bul
            y_in_container = self.tab_container.winfo_pointery() - self.tab_container.winfo_rooty()
            
            target_idx = current_idx
            for i, t in enumerate(self.tab_frames):
                btn_y = t["btn"].winfo_y()
                btn_h = t["btn"].winfo_height()
                # Fare bu sekmenin üzerindeyse hedef burasıdır
                if btn_y <= y_in_container <= btn_y + btn_h:
                    target_idx = i
                    break
            
            # Eğer yer değişimi varsa anında listede güncelle
            if target_idx != current_idx:
                self.tab_frames.pop(current_idx)
                self.tab_frames.insert(target_idx, dragged_tab)
                
                # Tüm sekmeleri yeni sıraya göre tekrar alt alta diz
                for t in self.tab_frames: t["btn"].pack_forget()
                for t in self.tab_frames: 
                    t["btn"].pack(side="top", fill="x", pady=2, padx=(5, 5))

        def on_release(e):
            if self._drag_data["tab"]:
                self._drag_data["tab"] = None
                # Sıralama bittiğinde veritabanına kaydet
                if self.on_reorder:
                    tab_names = [t["text"] for t in self.tab_frames]
                    self.on_reorder(tab_names)
                    
        # Olayları kutuya ve yazıya bağla
        for w in (btn, lbl, indicator):
            w.bind("<ButtonPress-1>", on_press)
            w.bind("<B1-Motion>", on_motion)
            w.bind("<ButtonRelease-1>", on_release)
        
        child.pack_forget()
        if len(self.tab_frames) == 1:
            self.select(child)
            
    def select(self, tab_id=None):
        if tab_id is None:
            return self.current_tab
            
        for tab in self.tab_frames:
            if tab["child"] == tab_id or tab["text"] == tab_id:
                if self.current_tab and self.current_tab != tab["child"]:
                    self.current_tab.pack_forget()
                    
                self.current_tab = tab["child"]
                self.current_tab.pack(in_=self.content_area, fill="both", expand=True)
                
                # --- AKTİF SEKME GÖRSELİ (ÖZEL TASARIM) ---
                for t in self.tab_frames:
                    if t["child"] == self.current_tab:
                        t["btn"].configure(bg=TM.get_color("card_bg"))
                        t["ind"].configure(bg=TM.get_color("btn_primary")) # Aktif Mavi Çizgi
                        t["lbl"].configure(bg=TM.get_color("card_bg"), fg=TM.get_color("btn_primary"))
                    else:
                        t["btn"].configure(bg=TM.get_color("bg_sidebar"))
                        t["ind"].configure(bg=TM.get_color("bg_sidebar"))
                        t["lbl"].configure(bg=TM.get_color("bg_sidebar"), fg="#94a3b8")
                
                self._ensure_visible(tab["btn"])
                return tab["child"]
                
    def _ensure_visible(self, btn):
        # Seçili sekme ekran dışında kaldıysa otomatik kaydır
        self.canvas.update_idletasks()
        canvas_height = self.canvas.winfo_height()
        btn_y = btn.winfo_y()
        btn_h = btn.winfo_height()
        
        yview = self.canvas.yview()
        total_h = self.tab_container.winfo_height()
        if total_h == 0: return
        
        view_start = yview[0] * total_h
        view_end = yview[1] * total_h
        
        if btn_y < view_start:
            self.canvas.yview_moveto(btn_y / total_h)
        elif btn_y + btn_h > view_end:
            self.canvas.yview_moveto((btn_y + btn_h - canvas_height + 40) / total_h)

    def forget(self, tab_id):
        for i, tab in enumerate(self.tab_frames):
            if tab["child"] == tab_id or tab["text"] == tab_id:
                tab["btn"].destroy()
                if self.current_tab == tab["child"]:
                    tab["child"].pack_forget()
                    self.current_tab = None
                self.tab_frames.pop(i)
                break

    def tabs(self):
        return [t["child"] for t in self.tab_frames]

    def tab(self, tab_id, option=None):
        for t in self.tab_frames:
            if t["child"] == tab_id:
                if option == "text":
                    return t["text"]
                return t
        return ""

class TakvimPopup(tk.Toplevel):
    def __init__(self, parent, entry_widget):
        super().__init__(parent)
        self.entry = entry_widget
        self.title("Tarih Seç")
        x = parent.winfo_pointerx(); y = parent.winfo_pointery()
        self.geometry(f"+{x}+{y}")
        self.configure(bg="white", padx=10, pady=10)
        self.resizable(False, False)
        self.transient(parent); self.grab_set()

        try:
            mevcut_str = self.entry.get()
            self.secili_tarih = datetime.strptime(mevcut_str, "%Y-%m-%d").date()
        except: self.secili_tarih = date.today()
        self.yil = self.secili_tarih.year; self.ay = self.secili_tarih.month
        self.arayuz_olustur()

    def arayuz_olustur(self):
        for widget in self.winfo_children(): widget.destroy()
        header = tk.Frame(self, bg="white"); header.pack(fill="x", pady=(0, 10))
        btn_stil = {"relief": "flat", "bg": "#f1f5f9", "width": 3, "cursor": "hand2"}
        tk.Button(header, text="<<", command=self.onceki_yil, **btn_stil).pack(side="left")
        tk.Button(header, text="<", command=self.onceki_ay, **btn_stil).pack(side="left", padx=2)
        tr_aylar = ["", "OCAK", "ŞUBAT", "MART", "NİSAN", "MAYIS", "HAZİRAN", "TEMMUZ", "AĞUSTOS", "EYLÜL", "EKİM", "KASIM", "ARALIK"]
        tk.Label(header, text=f"{tr_aylar[self.ay]} {self.yil}", font=("Segoe UI", 10, "bold"), bg="white", width=16).pack(side="left", padx=5)
        tk.Button(header, text=">", command=self.sonraki_ay, **btn_stil).pack(side="left", padx=2)
        tk.Button(header, text=">>", command=self.sonraki_yil, **btn_stil).pack(side="left")
        cal_frame = tk.Frame(self, bg="white"); cal_frame.pack()
        gunler_tr = ["Pzt", "Sal", "Çar", "Per", "Cum", "Cmt", "Paz"]
        for i, gun in enumerate(gunler_tr): tk.Label(cal_frame, text=gun, font=("Segoe UI", 8, "bold"), bg="white", fg="#94a3b8", width=4).grid(row=0, column=i, pady=(0,5))
        cal = calendar.monthcalendar(self.yil, self.ay); bugun = date.today()
        for r, hafta in enumerate(cal):
            for c, gun in enumerate(hafta):
                if gun == 0: continue
                bg_color = "#ffffff"; fg_color = "#0f172a"; font_weight = "normal"
                if self.yil == bugun.year and self.ay == bugun.month and gun == bugun.day:
                    bg_color = "#dbeafe"; fg_color = "#1d4ed8"; font_weight = "bold"
                btn = tk.Button(cal_frame, text=str(gun), width=4, relief="flat", bg=bg_color, fg=fg_color, font=("Segoe UI", 9, font_weight), cursor="hand2", command=lambda d=gun: self.tarih_sec(d))
                btn.grid(row=r+1, column=c, padx=1, pady=1)

    def onceki_ay(self):
        self.ay -= 1
        if self.ay < 1: self.ay = 12; self.yil -= 1
        self.arayuz_olustur()
    def sonraki_ay(self):
        self.ay += 1
        if self.ay > 12: self.ay = 1; self.yil += 1
        self.arayuz_olustur()
    def onceki_yil(self): self.yil -= 1; self.arayuz_olustur()
    def sonraki_yil(self): self.yil += 1; self.arayuz_olustur()
    def tarih_sec(self, gun):
        secilen = date(self.yil, self.ay, gun).strftime("%Y-%m-%d")
        self.entry.delete(0, tk.END); self.entry.insert(0, secilen); self.destroy()

def tarih_secici_bagla(frame, entry):
    btn = tk.Button(frame, text="📅", font=("Segoe UI", 9), cursor="hand2", relief="flat", bg="#e2e8f0", command=lambda: TakvimPopup(frame.winfo_toplevel(), entry))
    btn.pack(side="left", padx=(0, 0), fill="y")

